script:
// Global Sidebar & App Switcher Patches
(function() {
    if (typeof frappe !== 'undefined') {
        if (frappe.ui && frappe.ui.Sidebar && !frappe.ui.Sidebar.prototype._patched_setup) {
            const original_setup = frappe.ui.Sidebar.prototype.setup;
            frappe.ui.Sidebar.prototype.setup = function(workspace_title) {
                if (!workspace_title) {
                    workspace_title = "";
                }
                original_setup.call(this, workspace_title);
            };
            frappe.ui.Sidebar.prototype._patched_setup = true;
        }
        if (frappe.ui && frappe.ui.SidebarHeader && !frappe.ui.SidebarHeader.prototype._patched_add_app_item) {
            const original_add_app_item = frappe.ui.SidebarHeader.prototype.add_app_item;
            frappe.ui.SidebarHeader.prototype.add_app_item = function(item) {
                if (!item.icon && !item.icon_url) {
                    item.icon = "setting";
                }
                original_add_app_item.call(this, item);
            };
            frappe.ui.SidebarHeader.prototype._patched_add_app_item = true;
        }
    }
})();

